async function findOpenPullRequestForHead({
	env,
	owner,
	repository,
	head,
	base,
	options,
}: {
	env: RhapsodyGitHubEnv;
	owner: string;
	repository: string;
	head: string;
	base: string;
	options?: {
		octokit?: OctokitPullRequestClient;
	};
}): Promise<{
	number: number;
	htmlUrl: string;
	title: string;
	headRef: string;
	baseRef: string;
} | null> {
	const octokit = options?.octokit ?? new Octokit({ auth: env.GITHUB_TOKEN });
	const perPage = 100;
	let page = 1;
	let pulls: ListOpenPullsResponseData = [];
	try {
		while (true) {
			const response = await octokit.rest.pulls.list({
				owner,
				repo: repository,
				state: "open",
				head: `${owner}:${head}`,
				per_page: perPage,
				page,
				headers: {
					Accept: "application/vnd.github+json",
					"X-GitHub-Api-Version": "2022-11-28",
				},
			});

			pulls = [...pulls, ...response.data];

			if (response.data.length < perPage) {
				break;
			}

			const linkHeader = response.headers.link;
			if (!linkHeader?.includes('rel="next"')) {
				break;
			}

			page += 1;
		}
	} catch (error) {
		const status = getErrorStatus(error);
		throw new GitHubPullRequestError(
			status,
			owner,
			repository,
			"lookup",
			error instanceof Error ? error.message : "request failed",
		);
	}

	if (pulls.length === 0) {
		return null;
	}

	const candidate = pulls.find((pull) => pull.base.ref === base);
	if (!candidate) {
		return null;
	}

	return {
		number: candidate.number,
		htmlUrl: candidate.html_url,
		title: candidate.title,
		headRef: candidate.head.ref,
		baseRef: candidate.base.ref,
	};
}

async function createPullRequest(args: {
	env: RhapsodyGitHubEnv;
	owner: string;
	repository: string;
	title: string;
	body: string;
	head: string;
	base: string;
	options?: {
		octokit?: OctokitPullRequestClient;
	};
}): Promise<{
	number: number;
	htmlUrl: string;
	title: string;
	headRef: string;
	baseRef: string;
}> {
	const octokit =
		args.options?.octokit ?? new Octokit({ auth: args.env.GITHUB_TOKEN });
	let response: CreatePullRequestResponse;
	try {
		response = await octokit.rest.pulls.create({
			owner: args.owner,
			repo: args.repository,
			title: args.title,
			body: args.body,
			head: args.head,
			base: args.base,
			headers: {
				Accept: "application/vnd.github+json",
				"X-GitHub-Api-Version": "2022-11-28",
			},
		});
	} catch (error) {
		const status = getErrorStatus(error);
		throw new GitHubPullRequestError(
			status,
			args.owner,
			args.repository,
			"create",
			error instanceof Error ? error.message : "request failed",
		);
	}

	const created = response.data;
	return {
		number: created.number,
		htmlUrl: created.html_url,
		title: created.title,
		headRef: created.head.ref,
		baseRef: created.base.ref,
	};
}

function getErrorStatus(value: unknown): number {
	if (
		typeof value === "object" &&
		value !== null &&
		"status" in value &&
		typeof (value as { status?: unknown }).status === "number"
	) {
		return (value as { status: number }).status;
	}

	return 500;
}

